+    "SELECT id, content, created_at FROM messages WHERE chat_id = $1 AND content LIKE $2 ORDER BY created_at DESC LIMIT $3",
+    [chatId, pattern, limit],
+  );
+  return rows.map((r) => ({
+    chatId,
+    messageId: r.id,
+    content: r.content,
+    createdAt: r.created_at,
+  }));
